# Generated by openai (gpt-5.2)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
  agent any

  options {
    disableConcurrentBuilds()
    timestamps()
    ansiColor('xterm')
    buildDiscarder(logRotator(numToKeepStr: '30', artifactNumToKeepStr: '10'))
    skipDefaultCheckout(true)
    timeout(time: 2, unit: 'HOURS')
  }

  parameters {
    choice(
      name: 'SHELL',
      choices: ['bash', 'sh', 'zsh'],
      description: 'Shell to use for executing commands. (bash recommended)'
    )

    booleanParam(
      name: 'DO_CHECKOUT',
      defaultValue: true,
      description: 'Checkout source code from SCM before running commands.'
    )

    string(
      name: 'CHECKOUT_REF',
      defaultValue: '',
      description: 'Optional: Git branch/tag/commit to checkout (when supported by SCM checkout). Leave empty to use Jenkinsfile SCM ref.'
    )

    text(
      name: 'BUILD_COMMANDS',
      defaultValue: '''set -euo pipefail
echo "No build commands provided."
''',
      description: 'Shell commands for build step. Multiple lines supported.'
    )

    text(
      name: 'TEST_COMMANDS',
      defaultValue: '''set -euo pipefail
echo "No test commands provided."
''',
      description: 'Shell commands for test step. Multiple lines supported.'
    )

    text(
      name: 'DEPLOY_COMMANDS',
      defaultValue: '''set -euo pipefail
echo "No deploy commands provided."
''',
      description: 'Shell commands for deploy step. Multiple lines supported.'
    )

    booleanParam(
      name: 'RUN_BUILD',
      defaultValue: true,
      description: 'Run build stage.'
    )

    booleanParam(
      name: 'RUN_TESTS',
      defaultValue: true,
      description: 'Run test stage.'
    )

    booleanParam(
      name: 'RUN_DEPLOY',
      defaultValue: false,
      description: 'Run deploy stage.'
    )

    booleanParam(
      name: 'DEPLOY_ONLY_ON_MAIN',
      defaultValue: true,
      description: 'If true, deploy only when building the main/master branch (or when BRANCH_NAME is unavailable).'
    )

    booleanParam(
      name: 'PRINT_ENV',
      defaultValue: false,
      description: 'Print environment variables (sanitized) before execution.'
    )

    booleanParam(
      name: 'DRY_RUN',
      defaultValue: false,
      description: 'If true, print commands but do not execute them.'
    )
  }

  environment {
    DEFAULT_SHELL = 'bash'
  }

  stages {
    stage('Checkout') {
      when { expression { return params.DO_CHECKOUT } }
      steps {
        checkout scm
        script {
          if (params.CHECKOUT_REF?.trim()) {
            sh(label: "Checkout ref: ${params.CHECKOUT_REF}", script: """
              set -euo pipefail
              git fetch --all --tags --prune
              git checkout '${params.CHECKOUT_REF.replace("'", "'\\''")}'
            """.stripIndent())
          }
        }
      }
    }

    stage('Preflight') {
      steps {
        script {
          def chosenShell = (params.SHELL ?: env.DEFAULT_SHELL).trim()
          if (!['bash', 'sh', 'zsh'].contains(chosenShell)) {
            error("Unsupported shell: ${chosenShell}")
          }
          env.CHOSEN_SHELL = chosenShell

          if (params.PRINT_ENV) {
            sh(label: 'Print environment (sanitized)', script: """
              set +x
              env | sort | sed -E 's/(PASS|PASSWORD|TOKEN|SECRET|KEY|CREDENTIALS)=.*/\\1=***REDACTED***/I'
            """.stripIndent())
          }
        }
      }
    }

    stage('Build') {
      when { expression { return params.RUN_BUILD } }
      steps {
        script {
          runUserCommands("Build", params.BUILD_COMMANDS)
        }
      }
    }

    stage('Test') {
      when { expression { return params.RUN_TESTS } }
      steps {
        script {
          runUserCommands("Test", params.TEST_COMMANDS)
        }
      }
    }

    stage('Deploy') {
      when {
        expression {
          if (!params.RUN_DEPLOY) return false
          if (!params.DEPLOY_ONLY_ON_MAIN) return true
          def bn = (env.BRANCH_NAME ?: '').trim()
          if (!bn) return true
          return (bn == 'main' || bn == 'master')
        }
      }
      steps {
        script {
          runUserCommands("Deploy", params.DEPLOY_COMMANDS)
        }
      }
    }
  }

  post {
    always {
      script {
        currentBuild.description = [
          "Shell=${params.SHELL}",
          "Checkout=${params.DO_CHECKOUT}",
          "Build=${params.RUN_BUILD}",
          "Tests=${params.RUN_TESTS}",
          "Deploy=${params.RUN_DEPLOY}"
        ].join(' | ')
      }
    }
  }
}

def runUserCommands(String stageName, String commandsText) {
  def cmds = (commandsText ?: '').trim()
  if (!cmds) {
    echo "${stageName}: No commands provided; skipping."
    return
  }

  if (params.DRY_RUN) {
    echo "DRY_RUN is enabled. ${stageName} commands (not executed):\n${cmds}"
    return
  }

  def shell = (env.CHOSEN_SHELL ?: 'bash').trim()

  if (shell == 'bash') {
    sh(
      label: "${stageName}: bash",
      shell: '/bin/bash',
      script: """
        set -euo pipefail
        ${cmds}
      """.stripIndent()
    )
  } else if (shell == 'zsh') {
    sh(
      label: "${stageName}: zsh",
      shell: '/bin/zsh',
      script: """
        set -euo pipefail
        ${cmds}
      """.stripIndent()
    )
  } else {
    sh(
      label: "${stageName}: sh",
      script: """
        set -e
        ${cmds}
      """.stripIndent()
    )
  }
}